PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?writer ?writerLabel ?episodeLabel WHERE {
  {
    SELECT ?episode WHERE {
      ?episode wdt:P179 wd:Q5930 ;
               wdt:P577 ?date .
    }
    ORDER BY ?date
    LIMIT 1 OFFSET 193
  }
  ?episode wdt:P161 wd:Q37175 .
  ?episode wdt:P58 ?writer .
  ?writer rdfs:label ?writerLabel .
  ?episode rdfs:label ?episodeLabel .
  FILTER(LANG(?writerLabel) = "en")
  FILTER(LANG(?episodeLabel) = "en")
}

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?episode ?episodeLabel ?seasonNo ?episodeNo ?writer ?writerLabel WHERE {
  ?episode wdt:P179 wd:Q5930 ;
           wdt:P1545 ?seasonNo ;
           wdt:P1548 ?episodeNo ;
           wdt:P161 wd:Q37175 ;
           wdt:P58 ?writer .
  ?episode rdfs:label ?episodeLabel .
  ?writer rdfs:label ?writerLabel .
  FILTER(LANG(?episodeLabel) = "en")
  FILTER(LANG(?writerLabel) = "en")
  FILTER(?seasonNo = "10" && ?episodeNo = "16")
}
ORDER BY xsd:integer(?seasonNo) xsd:integer(?episodeNo)
LIMIT 1

PREFIX wdt: <http://www.wikidata.org/prop/direct/>
PREFIX wd: <http://www.wikidata.org/entity/>

SELECT ?episode ?title ?date WHERE {
  ?episode wdt:P179 wd:Q5930 ;
           wdt:P161 wd:Q37175 ;
           rdfs:label ?title ;
           wdt:P577 ?date .
  FILTER (LANG(?title) = "en")
}
ORDER BY ?date
